import re import random # 定义规则库:模式(正则表达式) -&gt; 响应模板列表 rules = { r&#39;I need (.*)&#39;: [ &#34;Why do you need {0}?&#34;, &#34;Would it really help you to get {0}?&#34;, &#34;Are you sure you need {0}?&#34; ], r&#39;Why don\&#39;t you (.*)\?&#39;: [ &#34;Do you really think I don&#39;t {0}?&#34;, &#34;Perhaps eventually I will {0}.&#34;, &#34;Do you really want me to {0}?&#34; ], r&#39;Why can\&#39;t I (.*)\?&#39;: [ &#34;Do you think you should be able to {0}?&#34;, &#34;If you could {0}, what would you do?&#34;, &#34;I don&#39;t know -- why can&#39;t you {0}?&#34; ], r&#39;I am (.*)&#39;: [ &#34;Did you come to me because you are {0}?&#34;, &#34;How long have you been {0}?&#34;, &#34;How do you feel about being {0}?&#34; ], r&#39;.* mother .*&#39;: [ &#34;Tell me more about your mother.&#34;, &#34;What was your relationship with your mother like?&#34;, &#34;How do you feel about your mother?&#34; ], r&#39;.* father .*&#39;: [ &#34;Tell me more about your father.&#34;, &#34;How did your father make you feel?&#34;, &#34;What has your father taught you?&#34; ], r&#39;.*&#39;: [ &#34;Please tell me more.&#34;, &#34;Let&#39;s change focus a bit... Tell me about your family.&#34;, &#34;Can you elaborate on that?&#34; ] } # 定义代词转换规则 pronoun_swap = { &#34;i&#34;: &#34;you&#34;, &#34;you&#34;: &#34;i&#34;, &#34;me&#34;: &#34;you&#34;, &#34;my&#34;: &#34;your&#34;, &#34;am&#34;: &#34;are&#34;, &#34;are&#34;: &#34;am&#34;, &#34;was&#34;: &#34;were&#34;, &#34;i&#39;d&#34;: &#34;you would&#34;, &#34;i&#39;ve&#34;: &#34;you have&#34;, &#34;i&#39;ll&#34;: &#34;you will&#34;, &#34;yours&#34;: &#34;mine&#34;, &#34;mine&#34;: &#34;yours&#34; } def swap_pronouns(phrase): &#34;&#34;&#34; 对输入短语中的代词进行第一/第二人称转换 &#34;&#34;&#34; words = phrase.lower().split() swapped_words = [pronoun_swap.get(word, word) for word in words] return &#34; &#34;.join(swapped_words) def respond(user_input): &#34;&#34;&#34; 根据规则库生成响应 &#34;&#34;&#34; for pattern, responses in rules.items(): match = re.search(pattern, user_input, re.IGNORECASE) if match: # 捕获匹配到的部分 captured_group = match.group(1) if match.groups() else &#39;&#39; # 进行代词转换 swapped_group = swap_pronouns(captured_group) # 从模板中随机选择一个并格式化 response = random.choice(responses).format(swapped_group) return response # 如果没有匹配任何特定规则，使用最后的通配符规则 return random.choice(rules[r&#39;.*&#39;]) # 主聊天循环 if __name__ == &#39;__main__&#39;: print(&#34;Therapist: Hello! How can I help you today?&#34;) while True: user_input = input(&#34;You: &#34;) if user_input.lower() in [&#34;quit&#34;, &#34;exit&#34;, &#34;bye&#34;]: print(&#34;Therapist: Goodbye. It was nice talking to you.&#34;) break response = respond(user_input) print(f&#34;Therapist: {response}&#34;) 局限性：缺乏语义理解，无上下文记忆，规则的扩展性问题
智能体发展研究范式和演进 人工智能体的发展史并非一条笔直的单行道，而是几大核心思想流派长达半个多世纪交织、竞争与融合的历程。理解这一历程，有助于我们洞察当前智能体架构范式形成的深刻根源。
这其中，主要有三大思潮主导着不同时期的研究范式：
符号主义 (Symbolism) ：以赫伯特·西蒙 (Herbert A. Simon) 、明斯基 (Marvin Minsky) 等先驱为代表，认为智能的核心在于对符号的操作与逻辑推理。这一思想催生了能够理解自然语言指令的SHRDLU、知识驱动的专家系统以及在国际象棋领域取得巨大成功的“深蓝”计算机。 联结主义 (Connectionism) ：其灵感源于对大脑神经网络的模拟。尽管早期发展受限，但在杰弗里·辛顿 (Geoffrey Hinton) 等研究者的推动下，反向传播算法为神经网络的复苏奠定了基础。最终，随着深度学习时代的到来，这一思想通过卷积神经网络、Transformer等模型成为当前的主流。 行为主义 (Behaviorism) ：强调智能体通过与环境的互动和试错来学习最优策略，其现代化身为强化学习 。从早期的TD-Gammon到与深度学习结合并击败人类顶尖棋手的AlphaGo，这一流派为智能体赋予了从经验中习得复杂决策行为的能力。
进入21世纪20年代，这些思想流派以前所未有的方式深度融合。以GPT系列为代表的大语言模型，其本身是联结主义的产物，却成为了执行符号推理、进行工具调用和规划决策的核心“大脑”，形成了神经-符号结合的现代智能体架构。为了系统性地回顾这一发展脉络，下图2.11梳理了从20世纪50年代至今，人工智能体发展史上的关键理论、项目与事件，为读者提供一个清晰的全局概览，作为本章知识的沉淀。
第三章:大语言模型基础 本地部署大语言模型 选择了一个小规模但功能强大的模型：Qwen/Qwen1.5-0.5B-Chat。这是一个由阿里巴巴达摩院开源的拥有约 5 亿参数的对话模型，它体积小、性能优异，非常适合入门学习和本地部署。
pip install transformers torch 在 transformers 库中，我们通常使用 AutoModelForCausalLM 和 AutoTokenizer 这两个类来自动加载与模型匹配的权重和分词器。
import torch from transformers import AutoModelForCausalLM, AutoTokenizer # 指定模型ID model_id = &#34;Qwen/Qwen1.5-0.5B-Chat&#34; # 设置设备，优先使用GPU device = &#34;cuda&#34; if torch.cuda.is_available() else &#34;cpu&#34; print(f&#34;Using device: {device}&#34;) # 加载分词器 tokenizer = AutoTokenizer.from_pretrained(model_id) # 加载模型，并将其移动到指定设备 model = AutoModelForCausalLM.from_pretrained(model_id).to(device) print(&#34;模型和分词器加载完成！&#34;) # 准备对话输入 messages = [ {&#34;role&#34;: &#34;system&#34;, &#34;content&#34;: &#34;You are a helpful assistant.&#34;}, {&#34;role&#34;: &#34;user&#34;, &#34;content&#34;: &#34;介绍你自己。} ] # 使用分词器的模板格式化输入 text = tokenizer.apply_chat_template( messages, tokenize=False, add_generation_prompt=True ) # 编码输入文本 model_inputs = tokenizer([text], return_tensors=&#34;pt&#34;).to(device) print(&#34;编码后的输入文本:&#34;) print(model_inputs) # 使用模型生成回答 # max_new_tokens 控制了模型最多能生成多少个新的Token generated_ids = model.generate( model_inputs.input_ids, max_new_tokens=512 ) # 将生成的 Token ID 截取掉输入部分 # 这样我们只解码模型新生成的部分 generated_ids = [ output_ids[len(input_ids):] for input_ids, output_ids in zip(model_inputs.input_ids, generated_ids) ] # 解码生成的 Token ID response = tokenizer.batch_decode(generated_ids, skip_special_tokens=True)[0] print(&#34;
模型的回答:&#34;) print(response)
